// Internal component — not exported from @arvo/react public API.
// Used inside form controls (ArvoTextbox, ArvoSelect, etc.) to render the label.

interface FormLabelProps {
  htmlFor: string;
  id?: string;
  size?: 'sm' | 'lg';
  isRequired?: boolean;
  isDisabled?: boolean;
  className?: string;
  children: React.ReactNode;
}

export function FormLabel({
  htmlFor,
  id,
  size = 'lg',
  isRequired,
  isDisabled,
  className,
  children,
}: FormLabelProps) {
  const classes = [
    'arvo-form-lbl',
    size === 'sm' && 'arvo-form-lbl--sm',
    isRequired && 'arvo-form-lbl--required',
    isDisabled && 'is-disabled',
    className,
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <label id={id} htmlFor={htmlFor} className={classes}>
      {children}
      {isRequired && (
        <span className="arvo-form-lbl__req" aria-hidden="true">
          *
        </span>
      )}
    </label>
  );
}
